const [params, setParams] = useState(() => buildDefaultParams());

// ---------------- UPLOAD ----------------
const handleUpload = async (e) => {
  const file = e.target.files[0];
  if (!file) return;

  try {
    await uploadDataset(file); // ✅ FIX
    onNotify("📂 Dataset uploadé avec succès !", "success");
  } catch (err) {
    onNotify(`❌ Upload échoué : ${err.message}`, "error");
  }
};

// ---------------- TRAIN ----------------
const handleTrain = async () => {
  setTraining(true);
  setProgress(0);

  const tick = setInterval(() => {
    setProgress((p) => Math.min(p + 2, 88));
  }, 180);

  try {
    const newResults = {};

    for (const mid of selectedModels) {
      const res = await trainModel({
        model_id: mid,
        params: params[mid] || {}
      });

      newResults[mid] = res;
    }

    clearInterval(tick);
    setProgress(100);

    onTrainComplete(newResults);
    onNotify("✅ Training terminé", "success");

  } catch (err) {
    clearInterval(tick);
    onNotify(`❌ ${err.message}`, "error");
  } finally {
    setTimeout(() => {
      setTraining(false);
      setProgress(0);
    }, 500);
  }
};
